#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        char last = s[N-1];
        int ok=0;
        for(int i=0;i<N-1;i++) if(s[i]==last){ok=1;break;}
        puts(ok?"YES":"NO");
    }
    return 0;
}

